export function calculateExecutionStats() {
  const workflows = workflowsData.data || [];
  const executions = executionsData.data || [];

  const totalWorkflows = workflows.length;
  const activeWorkflows = workflows.filter(w => w.active).length;
  const inactiveWorkflows = totalWorkflows - activeWorkflows;
  const recentExecutions = executions.length;
  const successfulExecutions = executions.filter(e => e.status === 'success').length;
  const failedExecutions = executions.filter(e => e.status === 'error' || e.status === 'failed').length;

  return {
    totalWorkflows,
    activeWorkflows,
    inactiveWorkflows,
    recentExecutions,
    successfulExecutions,
    failedExecutions
  };
}

/**
 * Calculate execution stats per workflow
 * @returns {Object} Map of workflowId to stats {total, success, failed}
 */
export function getWorkflowStats() {
  const executions = executionsData.data || [];
  const workflowStats = {};
  
  executions.forEach(ex => {
    const wfId = ex.workflowId;
    if (!workflowStats[wfId]) {
      workflowStats[wfId] = { total: 0, success: 0, failed: 0 };
    }
    workflowStats[wfId].total++;
    if (ex.status === 'success') workflowStats[wfId].success++;
    if (ex.status === 'error' || ex.status === 'failed') workflowStats[wfId].failed++;
  });

  return workflowStats;
}
